INSERT INTO `noticias` VALUES (4,'📢 Atualizações e Novidades','A página VIO foi atualizada. A versão antiga, com os QR Codes antigos, continua ativa normalmente.','2026-02-16 10:07:29'),(5,'📢 Atualizações e Novidades','Agora contamos com a opção de acervo na galeria de imagens ao criar acessos de clientes, permitindo reutilizar fotos e assinaturas já salvas para gerar um novo acesso com mais rapidez e praticidade. 🚀','2026-02-16 10:07:38'),(6,'📢 Atualizações e Novidades','A base foi atualizada e estamos realizando algumas mudanças para melhorar a experiência de uso.\n\nNa versão mobile, a interface está mais minimalista e organizada. A aba Histórico de Serviços foi removida do menu principal e agora está localizada dentro da seção Serviços, deixando a navegação mais simples.\n\nOutra novidade é que, nos módulos onde é possível visualizar o documento antes de finalizar, removemos o botão “Gerar Preview”*. Agora, qualquer informação inserida é atualizada e renderizada automaticamente em tempo real, permitindo visualizar o resultado ao vivo enquanto você digita.','2026-03-09 12:12:20');
/*!40000 ALTER TABLE `noticias` ENABLE KEYS */;
UNLOCK TABLES;

